INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.5.17','cb','cb.adi.5','ЧБ Ади 5.17',17,'পরম-সুকৃতি এক তৈর্থিক ব্রাহ্মণ ।
কৃষ্ণের উদ্দেশে করে তীর্থ পর্য্যটন ॥১৭॥','парама-сукр̣ти эка таиртхика бра̄хман̣а
кр̣ш̣н̣ера уддеш́е каре тӣртха парйат̣ана',NULL,NULL),('cb.adi.5.18','cb','cb.adi.5','ЧБ Ади 5.18',18,'ষড়ক্ষর গোপালমন্ত্রের করে উপাসন ।
গোপাল-নৈবেদ্য বিনা না করে ভোজন ॥১৮॥','ш̣ад̣-акш̣ара гопа̄ла-мантрера каре упа̄сана
гапа̄ла-наиведйа вина̄ на̄ каре бходжана',NULL,NULL),('cb.adi.5.19','cb','cb.adi.5','ЧБ Ади 5.19',19,'দৈবে ভাগ্যবান্ তীর্থ ভ্রমিতে ভ্রমিতে ।
আসিয়া মিলিলা বিপ্র প্রভুর বাড়ীতে ॥১৯॥','даиве бха̄гйава̄н тӣртха бхрамите бхрамите
а̄сийа̄ милила̄ випра прабхура ба̄д̣ӣте',NULL,NULL),('cb.adi.5.20','cb','cb.adi.5','ЧБ Ади 5.20',20,'কণ্ঠে বালগোপাল ভূষণ শালগ্রাম ।
পরমব্রহ্মণ্য-তেজ, অতি অনুপম ॥২০॥','кан̣т̣хе ба̄ла-гопа̄ла бхӯш̣ан̣а ш́а̄лагра̄ма
парама-бра̄хман̣йа-теджа, ати анупама',NULL,NULL),('cb.adi.5.21','cb','cb.adi.5','ЧБ Ади 5.21',21,'নিরবধি মুখে বিপ্র ‘কৃষ্ণ কৃষ্ণ’ বোলে ।
অন্তরে গোবিন্দ-রসে দুইচক্ষু ঢুলে ॥২১॥','ниравадхи мукхе випра ‘кр̣ш̣н̣а кр̣ш̣н̣а’ боле
антаре говинда-расе дуи-чакш̣у дхуле',NULL,NULL),('cb.adi.5.22','cb','cb.adi.5','ЧБ Ади 5.22',22,'দেখি’ জগন্নাথ-মিশ্র তেজ সে তাঁহার ।
সম্ভ্রমে উঠিয়া করিলেন নমস্কার ॥২২॥','декхи’ джаганна̄тха-миш́ра теджа се та̄н̇ха̄ра
самбхраме ут̣хийа̄ карилена намаска̄ра',NULL,NULL),('cb.adi.5.23','cb','cb.adi.5','ЧБ Ади 5.23',23,'অতিথি-ব্যভার-ধর্ম্ম যেন-মতে হয় ।
সব করিলেন জগন্নাথ মহাশয় ॥২৩॥','атитхи-вйабха̄ра-дхарма йена-мате хайа
саба карилена джаганна̄тха маха̄ш́айа',NULL,NULL),('cb.adi.5.24','cb','cb.adi.5','ЧБ Ади 5.24',24,'আপনে করিয়া তান পাদ প্রক্ষালন ।
বসিতে দিলেন আনি’ উত্তম আসন ॥২৪॥','а̄пане карийа̄ та̄на па̄да пракш̣а̄лана
васите дилена а̄ни’ уттама а̄сана',NULL,NULL),('cb.adi.5.25','cb','cb.adi.5','ЧБ Ади 5.25',25,'সুস্থ হই’ বসিলেন যদি বিপ্রবর ।
তবে তানে মিশ্র জিজ্ঞাসেন, “কোথা ঘর ” ॥২৫॥','табе та̄не миш́ра джиджн̃а̄сена,—‘котха̄ гхара?’',NULL,NULL),('cb.adi.5.26','cb','cb.adi.5','ЧБ Ади 5.26',26,'বিপ্র বোলে, “আমি উদাসীন দেশান্তরী ।
চিত্তের বিক্ষেপে মাত্র পর্য্যটন করি” ॥২৬','випра боле,—‘а̄ми уда̄сӣна деш́а̄нтарӣ
читтера викш̣епе ма̄тра парйат̣ана кари’',NULL,NULL),('cb.adi.5.27','cb','cb.adi.5','ЧБ Ади 5.27',27,'প্রণতি করিয়া মিশ্র বোলেন বচন ।
“জগতের ভাগ্যে সে তোমার পর্য্যটন ॥২৭॥','пран̣ати карийа̄ миш́ра болена вачана
‘джагатера бха̄гйе се тома̄ра парйат̣ана',NULL,NULL),('cb.adi.5.28','cb','cb.adi.5','ЧБ Ади 5.28',28,'বিশেষতঃ আজি আমার পরম সৌভাগ্য ।
আজ্ঞা দেহ’,—রন্ধনের করি গিয়া কার্য্য” ॥২৮॥
বিপ্র বোলে, “কর, মিশ্র, যে ইচ্ছা তোমার” ।
হরিষে করিলা মিশ্র দিব্য উপহার ॥২৯॥
রন্ধনের স্থান উপস্করি’ ভাল-মতে ।
দিলেন সকল সজ্জ রন্ধন করিতে ॥৩০॥','виш́еш̣атах̣ а̄джи а̄ма̄ра парама саубха̄гйа
а̄джн̃а̄ деха’,—рандханера кари гийа̄ ка̄рйа’
випра боле, — ‘кара, миш́ра, йе иччха̄ тома̄ра’
хариш̣е карила̄ миш́ра дивйа упаха̄ра
рандханера стха̄на упаскари’ бха̄ла-мате',NULL,NULL),('cb.adi.5.31','cb','cb.adi.5','ЧБ Ади 5.31',31,'সন্তোষে ব্রাহ্মণবর করিয়া রন্ধন ।
বসিলেন কৃষ্ণেরে করিতে নিবেদন ॥৩১॥','сантош̣е бра̄хман̣а-вара карийа̄ рандхана
василена кр̣ш̣н̣ере карите ниведана',NULL,NULL),('cb.adi.5.32','cb','cb.adi.5','ЧБ Ади 5.32',32,'সর্ব্বভূত-অন্তর্যামী শ্রীশচীনন্দন ।
মনে আছে,—বিপ্রেরে দিবেন দরশন ॥৩২॥','сарва-бхӯта-антарйа̄мӣ ш́рӣ-ш́ачӣнандана
мане а̄чхе,— випрере дибена дараш́ана',NULL,NULL),('cb.adi.5.33','cb','cb.adi.5','ЧБ Ади 5.33',33,'ধ্যানমাত্র করিতে লাগিলা বিপ্রবর ।
সম্মুখে আইলা প্রভু শ্রীগৌরসুন্দর ॥৩৩॥','дхйа̄на-ма̄тра карите ла̄гила випра-вара
саммукхе а̄ила̄ прабху ш́рӣ-гаурасундара',NULL,NULL),('cb.adi.5.34','cb','cb.adi.5','ЧБ Ади 5.34',34,'ধূলাময় সর্ব্ব-অঙ্গ, মূর্ত্তি দিগম্বর ।
অরুণ নয়ন, কর-চরণ সুন্দর ॥৩৪॥','дхӯла-майа сарва-ан̇га, мӯрти дигамбара
арун̣а-найана, кара-чаран̣а сундара',NULL,NULL),('cb.adi.5.35','cb','cb.adi.5','ЧБ Ади 5.35',35,'হাসিয়া বিপ্রের অন্ন লইলা শ্রীকরে ।
এক গ্রাস খাইলেন, দেখে বিপ্রবরে ॥৩৫॥','ха̄сийа̄ випрера анна лаийа̄ ш́рӣ-каре
эка гра̄са кха̄илена, декхе випра-варе',NULL,NULL),('cb.adi.5.36','cb','cb.adi.5','ЧБ Ади 5.36',36,'‘হায় হায়’ করি’ ভাগ্যবন্ত বিপ্র ডাকে ।
“অন্ন চুরি করিলেক চঞ্চল বালকে” ॥৩৬॥','‘ха̄йа ха̄йа’ кари’ бха̄гйаванта випра д̣а̄ке
‘анна чури карилека чан̃чала ба̄лаке’',NULL,NULL),('cb.adi.5.37','cb','cb.adi.5','ЧБ Ади 5.37',37,'আসিয়া দেখেন জগন্নাথ-মিশ্রবর ।
ভাত খায়, হাসে প্রভু শ্রীগৌরসুন্দর ॥৩৭॥','а̄сийа̄ декхена джаганна̄тха-миш́ра-вара
бха̄та кха̄йа, ха̄се прабху ш́рӣ-гаурасундара',NULL,NULL),('cb.adi.5.38','cb','cb.adi.5','ЧБ Ади 5.38',38,'ক্রোধে মিশ্র ধাইয়া যায়েন মারিবারে ।
সম্ভ্রমে উঠিয়া বিপ্র ধরিলেন করে ॥৩৮॥','кродхе миш́ра дха̄ийа̄ йа̄йена ма̄риба̄ре
самбхраме ут̣хийа̄ випра дхарилена каре',NULL,NULL),('cb.adi.5.39','cb','cb.adi.5','ЧБ Ади 5.39',39,'বিপ্র বোলে, “মিশ্র, তুমি বড় দেখি আর্য্য !” ।
কোন্ জ্ঞান বালকের মারিয়া কি কার্য্য ॥৩৯॥','випра боле, — ‘миш́ра, туми бад̣а декхи а̄рйа!
кон джн̃а̄на ба̄лакера ма̄рийа̄ ки ка̄рйа?',NULL,NULL),('cb.adi.5.40','cb','cb.adi.5','ЧБ Ади 5.40',40,'ভাল-মন্দ-জ্ঞান যার থাকে, মারি তারে ।
আমার শপথ, যদি মারহ উহারে” ॥৪০॥','бха̄ла-манда-джн̃а̄на йа̄ра тха̄ке, ма̄ри та̄ре
а̄ма̄ра ш́апатха, йади ма̄раха уха̄ре’',NULL,NULL),('cb.adi.5.41','cb','cb.adi.5','ЧБ Ади 5.41',41,'দুঃখে বসিলেন মিশ্র হস্ত দিয়া শিরে ।
মাথা নাহি তোলে মিশ্র, বচন না স্ফুরে ॥৪১॥','дух̣кхе василена миш́ра хаста дийа̄ ш́ире
ма̄тха̄ на̄хи толе миш́ра, вачана на̄ спхуре',NULL,NULL),('cb.adi.5.42','cb','cb.adi.5','ЧБ Ади 5.42',42,'বিপ্র বোলে, “মিশ্র, দুঃখ না ভাবিহ মনে ।
যে দিনে যে হবে, তাহা ঈশ্বর সে জানে ॥৪২॥','випра боле, — ‘миш́ра, дух̣кха на̄ бха̄виха мане
йе дине йе хабе, та̄ха̄ ӣш́вара се джа̄не',NULL,NULL),('cb.adi.5.43','cb','cb.adi.5','ЧБ Ади 5.43',43,'ফল-মূল-আদি গৃহে যে থাকে তোমার ।
আনি’ দেহ’ আজি তাহা করিব আহার” ॥৪৩॥','пхала-мӯла-а̄ди гр̣хе йе тха̄ке тома̄ра
а̄ни’ деха’ а̄джи та̄ха̄ кариба а̄ха̄ра’',NULL,NULL),('cb.adi.5.44','cb','cb.adi.5','ЧБ Ади 5.44',44,'মিশ্র বোলে, “মোরে যদি থাকে ভৃত্য-জ্ঞান ।
আর-বার পাক কর, করি দেঙ স্থান ॥৪৪॥','миш́ра боле, — ‘море йади тха̄ке бхр̣тйа-джн̃а̄на
а̄ра-ба̄ра па̄ка кара, кари’ ден̇а стха̄на',NULL,NULL),('cb.adi.5.45','cb','cb.adi.5','ЧБ Ади 5.45',45,'গৃহে আছে রন্ধনের সকল সম্ভার ।
পুনঃ পাক কর, তবে সন্তোষ আমার” ॥৪৫॥','гр̣хе а̄чхе рандханера сакала самбха̄ра
пунах̣ па̄ка кара, табе сантош̣а а̄ма̄ра’',NULL,NULL),('cb.adi.5.46','cb','cb.adi.5','ЧБ Ади 5.46',46,'বলিতে লাগিলা যত ইষ্ট-বন্ধুগণ ।
“আমা-সবা’ চাহি’ তবে করহ রন্ধন” ॥৪৬॥','балите ла̄гийа̄ йата иш̣т̣а-бандху-ган̣а
‘а̄ма̄-саба̄’ ча̄хи’ табе караха рандхана’',NULL,NULL),('cb.adi.5.47','cb','cb.adi.5','ЧБ Ади 5.47',47,'বিপ্র বোলে, “যেই ইচ্ছা তোমা-সবাকার ।
করিব রন্ধন সর্ব্বথায় পুনর্ব্বার” ॥৪৭॥','випра боле, — ‘йеи иччха̄ тома̄-саба̄кара
кариба рандхана сарватха̄йа пунар-ба̄ра’',NULL,NULL),('cb.adi.5.48','cb','cb.adi.5','ЧБ Ади 5.48',48,'হরিষ হইলা সবে বিপ্রের বচনে ।
স্থান উপস্করিলেন সবে ততক্ষণে ॥৪৮॥','хариш̣а хаила̄ сабе випрера вачане
стха̄на упаскарилена сабе тата-кш̣ан̣е',NULL,NULL),('cb.adi.5.49','cb','cb.adi.5','ЧБ Ади 5.49',49,'রন্ধনের সজ্জ আনি’ দিলেন ত্বরিতে ।
চলিলেন বিপ্রবর রন্ধন করিতে ॥৪৯॥','рандханера саджджа а̄ни’ дилена тварите',NULL,NULL),('cb.adi.5.50','cb','cb.adi.5','ЧБ Ади 5.50',50,'সবেই বোলেন, “শিশু পরম চঞ্চল ।
আর-বার পাছে নষ্ট করয়ে সকল ॥৫০॥','сабеи болена, — ‘ш́иш́у парама чан̃чала
а̄ра ба̄ра па̄чхе наш̣т̣а карайе сакала’',NULL,NULL),('cb.adi.5.51','cb','cb.adi.5','ЧБ Ади 5.51',51,'রন্ধন, ভোজন বিপ্র করেন যাবৎ ।
আর-বাড়ী লয়ে শিশু রাখহ তাবৎ” ॥৫১॥','рандхана, бходжана випра карена йа̄ват
а̄ра-ба̄д̣и лайе ш́иш́у ра̄кхаха та̄ват’',NULL,NULL),('cb.adi.5.52','cb','cb.adi.5','ЧБ Ади 5.52',52,'তবে শচীদেবী পুত্ত্রে কোলে ত’ করিয়া ।
চলিলেন আর-বাড়ী প্রভুরে লইয়া ॥৫২॥','табе ш́ачӣдевӣ путре коле та’ карийа̄
чалилена а̄ра-ба̄д̣ӣ прабхуре лаийа̄',NULL,NULL),('cb.adi.5.53','cb','cb.adi.5','ЧБ Ади 5.53',53,'সব নারীগণ বোলে, “শুন রে নিমাই ।
এমত করিয়া কি বিপ্রের অন্ন খাই ” ॥৫৩॥','саба на̄рӣ-ган̣а боле, — ‘ш́уна ре нима̄и
эмата карийа̄ ки випрера анна кха̄и!’',NULL,NULL),('cb.adi.5.54','cb','cb.adi.5','ЧБ Ади 5.54',54,'হাসিয়া বোলেন প্রভু শ্রীচন্দ্রবদনে ।
“আমার কি দোষ িপ্র ডাকিলা আপনে” ॥৫৪॥
সবেই বোলেন, “অয়ে নিমাই ঢাঙ্গাতি ! ।
কি করিবা, এবে যে তোমার গেল জাতি ॥৫৫॥
কোথাকার ব্রাহ্মণ, কোন্ কুল, কেবা চিনে ।
তার ভাত খাই’ জাতি রাখিবা কেমনে ” ॥৫৬॥','ха̄сийа̄ болена прабху ш́рӣ-чандра-вадане
‘а̄ма̄ра ки дош̣а, випра д̣а̄кила̄ а̄пане?’
сабеи болена, — ‘айе нима̄и д̣ха̄н̇га̄ти!
ки кариба̄, эбе йе тома̄ра гела джа̄ти’
котха̄ка̄ра бра̄хман̣а, кон кула, кеба̄ чине?
та̄ра бха̄та кха̄и’ джа̄ти ра̄кхиба̄ кемане?’',NULL,NULL),('cb.adi.5.57','cb','cb.adi.5','ЧБ Ади 5.57',57,'হাসিয়া কহেন প্রভু, “আমি যে গোয়াল ! ।
ব্রাহ্মণের অন্ন আমি খাই সর্ব্বকাল ॥৫৭॥','ха̄сийа̄ кахена прабху,—‘а̄ми йе гойа̄ла!
бра̄хман̣ера анна а̄ми кха̄и сарва-ка̄ла',NULL,NULL),('cb.adi.5.58','cb','cb.adi.5','ЧБ Ади 5.58',58,'ব্রাহ্মণের অন্নে কি গোপের জাতি যায় ” ।
